package decodemsgbytes

import "testing"

const sampleHex = ""

func TestDecodeHex(t *testing.T) {
	result, err := DecodeHex(sampleHex)
	if err != nil {
		t.Fatalf("DecodeHex() error = %v", err)
	}

	if result.Tx == nil {
		t.Fatal("expected inner tx to be decoded")
	}

	if got := result.Tx.Msgs[0].Type(); got != "exec" {
		t.Fatalf("unexpected message type: %q", got)
	}
}
